AGENT_PROMPTS = {
    "planner": (
        "You are a task planner. Review the conversation and either break down the task "
        "into steps for the team, or assess progress and guide the next action. "
        "Be concise and directive."
    ),
    "coder": (
        "You are a software engineer. Implement what the planner requested. "
        "Write working Python code. Show only the code and a brief explanation."
    ),
    "reviewer": (
        "You are a code reviewer. Review the latest code from the coder. "
        "Point out specific issues or say LGTM if it looks correct."
    ),
}

def make_agent_node(agent_name: str, llm: ChatAnthropic):
    def node(state: GroupChatState) -> dict:
        history = format_history(state["messages"])
        system_prompt = AGENT_PROMPTS[agent_name]
        try:
            resp = llm.invoke([
                {"role": "system", "content": system_prompt},
                {"role": "user",   "content": (
                    f"Task: {state['task']}\n\nConversation so far:\n{history}"
                    if history else f"Task: {state['task']}"
                )},
            ])
            return {
                "messages": [{"role": agent_name, "content": resp.content}],
                "turn": state["turn"] + 1,
            }
        except Exception as exc:
            return {
                "messages": [{"role": agent_name, "content": f"[ERROR: {exc}]"}],
                "turn": state["turn"] + 1,
                "errors": [f"{agent_name}:{exc}"],
            }
    return node

planner_node  = make_agent_node("planner",  sonnet)
coder_node    = make_agent_node("coder",    haiku)
reviewer_node = make_agent_node("reviewer", haiku)

def llm_chat_manager(state: GroupChatState) -> str:
    if state["turn"] >= MAX_TURNS:
        return END

    history = format_history(state["messages"])
    resp = haiku.invoke([
        {"role": "system", "content": (
            f"You are managing a group chat with agents: {', '.join(AGENTS)}. "
            "Read the conversation and return ONLY the name of the agent who should speak next. "
            "Return DONE if the task is complete."
        )},
        {"role": "user", "content": f"Task: {state['task']}\n\n{history}"},
    ])
    choice = resp.content.strip().lower()
    if choice in AGENTS:
        return choice
    if "done" in choice:
        return END
    return AGENTS[state["turn"] % len(AGENTS)]   # fallback: round-robin

from unittest.mock import patch, MagicMock

def test_chat_manager_starts_with_planner():
    state = {"task": "test", "messages": [], "next_speaker": "",
             "turn": 0, "final": "", "errors": []}
    assert chat_manager(state) == "planner"

