             "messages": [{"role": "reviewer", "content": "LGTM looks good"}],
             "next_speaker": "", "turn": 3, "final": "", "errors": []}
    assert chat_manager(state) == END

def test_chat_manager_ends_at_max_turns():
    state = {"task": "test", "messages": [], "next_speaker": "",
             "turn": MAX_TURNS, "final": "", "errors": []}
    assert chat_manager(state) == END

