SUMMARIZE_THRESHOLD = 6   # compress when more than 6 messages

def maybe_summarize(state: GroupChatState) -> dict:
    """If history exceeds threshold, compress older messages into a summary."""
    messages = state["messages"]
    if len(messages) <= SUMMARIZE_THRESHOLD:
        return {}   # no action needed

    to_compress = messages[:-2]   # keep last 2 messages intact
    recent      = messages[-2:]

    history_text = format_history(to_compress)
    resp = haiku.invoke([
        {"role": "system", "content": "Summarise this conversation into a brief paragraph preserving key decisions and outputs."},
        {"role": "user",   "content": history_text},
    ])
    summary_message: ChatMessage = {
        "role": "system",
        "content": f"[SUMMARY OF EARLIER CONVERSATION]\n{resp.content}",
    }
    # Replace old messages with summary + recent messages
    return {"messages": [summary_message] + recent}

def make_agent_node_with_summarization(agent_name: str, llm: ChatAnthropic):
    """Like make_agent_node but triggers summarization before each turn if needed."""
    def node(state: GroupChatState) -> dict:
        # Compress history if needed (returns {} if not needed)
        compress_update = maybe_summarize(state)
        effective_messages = compress_update.get("messages", state["messages"])
        history = format_history(effective_messages)
        system_prompt = AGENT_PROMPTS[agent_name]
        try:
            resp = llm.invoke([
                {"role": "system", "content": system_prompt},
                {"role": "user",   "content": f"Task: {state['task']}\n\n{history}"},
            ])
            new_msg: ChatMessage = {"role": agent_name, "content": resp.content}
            updates: dict = {"messages": [new_msg], "turn": state["turn"] + 1}
            if compress_update:
                # Carry forward the compressed history as a reset
                updates["messages"] = compress_update["messages"] + [new_msg]
            return updates
        except Exception as exc:
            return {"messages": [{"role": agent_name, "content": f"[ERROR]"}],
                    "turn": state["turn"] + 1, "errors": [f"{agent_name}:{exc}"]}
    return node
